const{get:a,run:t}=require("../db");async function u(e){return a("SELECT id, username, email, password_hash, created_at FROM users WHERE username = ?",[e])}async function i(e){return a("SELECT id, username, email, password_hash, created_at FROM users WHERE email = ?",[e])}async function d(e){return a("SELECT id, username, email, created_at FROM users WHERE id = ?",[e])}async function c({username:e,email:s,passwordHash:n,createdAt:r}){return{id:(await t("INSERT INTO users (username, email, password_hash, created_at) VALUES (?, ?, ?, ?)",[e,s,n,r])).lastID,username:e,email:s,created_at:r}}module.exports={findByUsername:u,findByEmail:i,findById:d,createUser:c};
